import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { 
  Upload, 
  X, 
  Camera, 
  ArrowLeft,
  MapPin,
  FileText,
  AlertTriangle
} from 'lucide-react';
import toast from 'react-hot-toast';

const CreateComplaint = () => {
  const { api, user } = useAuth();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    blockNumber: '',
    buildingNumber: '',
    roomNumber: '',
    priority: 'MEDIUM',
    assetCategory: 'OTHER'
  });

  const categories = [
    { value: 'ELECTRICAL', label: 'Electrical' },
    { value: 'FURNITURE', label: 'Furniture' },
    { value: 'IT_INFRASTRUCTURE', label: 'IT / Computer' },
    { value: 'PLUMBING', label: 'Plumbing' },
    { value: 'AIR_CONDITIONING', label: 'AC / Cooling' },
    { value: 'LIFT', label: 'Lift / Elevator' },
    { value: 'CLEANING', label: 'Cleaning / Housekeeping' },
    { value: 'BUILDING_MAINTENANCE', label: 'Building / Civil' },
    { value: 'OTHER', label: 'Other' },
  ];
  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;

    // Special handling for blockNumber to only allow a single capital letter
    if (name === 'blockNumber') {
      const upperValue = value.toUpperCase();
      if (upperValue === '' || /^[A-Z]$/.test(upperValue)) {
        setFormData({
          ...formData,
          [name]: upperValue
        });
      }
      return;
    }

    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleFileChange = (e) => {
    const selectedFiles = Array.from(e.target.files);
    setFiles(selectedFiles);
  };

  const handleCameraCapture = async () => {
    try {
      // Request camera access
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });

      // Create video element to show camera feed
      const video = document.createElement('video');
      video.srcObject = stream;
      video.autoplay = true;

      // Create modal for camera capture
      const modal = document.createElement('div');
      modal.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: rgba(0,0,0,0.8);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 10000;
      `;

      const container = document.createElement('div');
      container.style.cssText = `
        background: white;
        padding: 20px;
        border-radius: 10px;
        max-width: 90%;
        max-height: 90%;
        position: relative;
      `;

      const videoContainer = document.createElement('div');
      videoContainer.style.cssText = `
        position: relative;
        margin-bottom: 10px;
      `;

      video.style.cssText = `
        max-width: 100%;
        max-height: 60vh;
        border-radius: 8px;
      `;

      const captureButton = document.createElement('button');
      captureButton.textContent = '📸 Capture Photo';
      captureButton.style.cssText = `
        background: #3b82f6;
        color: white;
        border: none;
        padding: 10px 20px;
        border-radius: 5px;
        cursor: pointer;
        margin-right: 10px;
        font-size: 16px;
      `;

      const cancelButton = document.createElement('button');
      cancelButton.textContent = '❌ Cancel';
      cancelButton.style.cssText = `
        background: #ef4444;
        color: white;
        border: none;
        padding: 10px 20px;
        border-radius: 5px;
        cursor: pointer;
        font-size: 16px;
      `;

      const buttonContainer = document.createElement('div');
      buttonContainer.style.cssText = `
        text-align: center;
      `;

      videoContainer.appendChild(video);
      buttonContainer.appendChild(captureButton);
      buttonContainer.appendChild(cancelButton);
      container.appendChild(videoContainer);
      container.appendChild(buttonContainer);
      modal.appendChild(container);
      document.body.appendChild(modal);

      const capturePhoto = () => {
        const canvas = document.createElement('canvas');
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(video, 0, 0);

        canvas.toBlob((blob) => {
          const file = new File([blob], `camera-photo-${Date.now()}.jpg`, { type: 'image/jpeg' });
          setFiles(prev => [...prev, file]);

          // Cleanup
          stream.getTracks().forEach(track => track.stop());
          document.body.removeChild(modal);

          toast.success('Photo captured successfully!');
        }, 'image/jpeg', 0.9);
      };

      captureButton.onclick = capturePhoto;
      cancelButton.onclick = () => {
        stream.getTracks().forEach(track => track.stop());
        document.body.removeChild(modal);
      };

      // Close modal on background click
      modal.onclick = (e) => {
        if (e.target === modal) {
          stream.getTracks().forEach(track => track.stop());
          document.body.removeChild(modal);
        }
      };

    } catch (error) {
      console.error('Camera access error:', error);
      if (error.name === 'NotAllowedError') {
        toast.error('Camera access denied. Please allow camera permissions.');
      } else if (error.name === 'NotFoundError') {
        toast.error('No camera found on this device.');
      } else {
        toast.error('Failed to access camera: ' + error.message);
      }
    }
  };

  const removeFile = (index) => {
    setFiles(files.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.title || !formData.description) {
      toast.error('Please fill in all required fields');
      return;
    }

    try {
      setUploading(true);

      console.log('Creating complaint with data:', formData);

      // Create complaint first
      const response = await api.post('/complaints', formData);
      const complaintId = response.data.id;

      // Upload files if any
      if (files.length > 0) {
        const formData = new FormData();
        files.forEach((file) => {
          formData.append('files', file);
        });
        formData.append('complaintId', complaintId);

        await api.post('/complaints/upload', formData, {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        });
      }

      toast.success('Complaint created successfully!');
      navigate('/complaints');
    } catch (error) {
      console.error('Error creating complaint:', error);
      console.error('Error response:', error.response);
      console.error('Error data:', error.response?.data);
      console.error('Error status:', error.response?.status);
      console.error('Error statusText:', error.response?.statusText);

      if (error.response?.status === 403) {
        toast.error('Permission denied. You may not have the correct role to create complaints.');
      } else {
        toast.error(error.response?.data?.message || 'Failed to create complaint');
      }
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <Link
            to="/complaints"
            className="inline-flex items-center text-gray-600 hover:text-gray-900 transition-colors"
          >
            <ArrowLeft className="h-5 w-5 mr-2" />
            Back to Complaints
          </Link>
          <div className="h-6 w-px bg-gray-300"></div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Create New Complaint</h1>
            <p className="text-gray-600 mt-1">Report infrastructure issues in your college</p>
          </div>
        </div>
      </div>

      {/* Form */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Title */}
          <div>
            <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-2">
              Complaint Title *
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <FileText className="h-5 w-5 text-gray-400" />
              </div>
              <input
                type="text"
                id="title"
                name="title"
                required
                className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                placeholder="Brief description of the issue"
                value={formData.title}
                onChange={handleChange}
              />
            </div>
          </div>

          {/* Description */}
          <div>
            <label htmlFor="description" className="block text-sm font-medium text-gray-700 mb-2">
              Detailed Description *
            </label>
            <textarea
              id="description"
              name="description"
              required
              rows="4"
              className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              placeholder="Provide detailed information about the issue, including when it started and how it affects you"
              value={formData.description}
              onChange={handleChange}
            />
          </div>

          {/* Location */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              <MapPin className="inline h-4 w-4 mr-1" />
              Location Details
            </label>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label htmlFor="blockNumber" className="block text-xs font-medium text-gray-600 mb-1">
                  Block (A, B, C...)
                </label>
                <input
                  type="text"
                  id="blockNumber"
                  name="blockNumber"
                  className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  maxLength="1"
                  placeholder="M"
                  value={formData.blockNumber}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label htmlFor="buildingNumber" className="block text-xs font-medium text-gray-600 mb-1">
                  Building Number
                </label>
                <input
                  type="text"
                  id="buildingNumber"
                  name="buildingNumber"
                  className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  placeholder="e.g., 1, 2, 3"
                  value={formData.buildingNumber}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label htmlFor="roomNumber" className="block text-xs font-medium text-gray-600 mb-1">
                  Room Number
                </label>
                <input
                  type="text"
                  id="roomNumber"
                  name="roomNumber"
                  className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  placeholder="e.g., 201, Lab-1"
                  value={formData.roomNumber}
                  onChange={handleChange}
                />
              </div>
            </div>
          </div>

          {/* Category & Priority */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label htmlFor="assetCategory" className="block text-sm font-medium text-gray-700 mb-2">
                Issue Category
              </label>
              <select
                id="assetCategory"
                name="assetCategory"
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                value={formData.assetCategory}
                onChange={handleChange}
              >
                {categories.map((cat) => (
                  <option key={cat.value} value={cat.value}>{cat.label}</option>
                ))}
              </select>
            </div>

            <div>
              <label htmlFor="priority" className="block text-sm font-medium text-gray-700 mb-2">
                <AlertTriangle className="inline h-4 w-4 mr-1" />
                Priority Level
              </label>
              <select
                id="priority"
                name="priority"
                className="block w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                value={formData.priority}
                onChange={handleChange}
              >
                <option value="LOW">Low - Minor issue</option>
                <option value="MEDIUM">Medium - Normal</option>
                <option value="HIGH">High - Important</option>
                <option value="URGENT">Urgent - Critical</option>
              </select>
            </div>
          </div>

          {/* File Upload */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              <Upload className="inline h-4 w-4 mr-1" />
              Attach Evidence (Optional)
            </label>

            {/* Camera and Upload Options */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              {/* Camera Capture */}
              <div 
                onClick={handleCameraCapture}
                className="border-2 border-dashed border-blue-300 rounded-lg p-4 text-center hover:border-blue-400 transition-colors cursor-pointer bg-blue-50"
              >
                <Camera className="mx-auto h-8 w-8 text-blue-500 mb-2" />
                <div className="text-sm text-blue-600">
                  <span className="font-medium">📸 Take Photo</span>
                </div>
                <p className="text-xs text-blue-500 mt-1">
                  Use device camera
                </p>
              </div>

              {/* File Upload */}
              <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 text-center hover:border-gray-400 transition-colors">
                <input
                  type="file"
                  id="file-upload"
                  multiple
                  accept="image/*,.pdf,.doc,.docx"
                  onChange={handleFileChange}
                  className="hidden"
                />
                <label htmlFor="file-upload" className="cursor-pointer">
                  <Upload className="mx-auto h-8 w-8 text-gray-400 mb-2" />
                  <div className="text-sm text-gray-600">
                    <span className="font-medium text-primary-600 hover:text-primary-500">📁 Upload Files</span>
                  </div>
                  <p className="text-xs text-gray-500 mt-1">
                    PNG, JPG, PDF, DOC
                  </p>
                </label>
              </div>
            </div>

            {/* File List */}
            {files.length > 0 && (
              <div className="mt-4 space-y-2">
                {files.map((file, index) => (
                  <div key={index} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center space-x-3">
                      <FileText className="h-5 w-5 text-gray-400" />
                      <div>
                        <p className="text-sm font-medium text-gray-900">{file.name}</p>
                        <p className="text-xs text-gray-500">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                      </div>
                    </div>
                    <button
                      type="button"
                      onClick={() => removeFile(index)}
                      className="text-red-500 hover:text-red-700 transition-colors"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Submit Buttons */}
          <div className="flex flex-col sm:flex-row gap-3 pt-6 border-t border-gray-200">
            <Link
              to="/complaints"
              className="inline-flex items-center justify-center px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors duration-200"
            >
              Cancel
            </Link>
            <button
              type="submit"
              disabled={uploading}
              className="inline-flex items-center justify-center px-6 py-3 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors duration-200"
            >
              {uploading ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                  Creating...
                </>
              ) : (
                <>
                  <Upload className="mr-2 h-4 w-4" />
                  Create Complaint
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CreateComplaint;
